class Solution {
    public long countGoodIntegers(int n, int k) {
        long[] digits = new long[10];
        for (int i = 1; i <= 9; i++) {
            digits[i] = 1;
        }
        long count = 0;
        if (n == 1) {
            for (int i = 0; i < 10; i++) {
                if (i % k == 0) {
                    count++;
                }
            }
            return count;
        }
        count = 0;
        for (int i = 1; i <= 9; i++) {
            count += helper(n - 1, k, i, digits, true);
        }
        return count;
    }

    private long helper(int n, int k, int last, long[] digits, boolean limit) {
        if (n == 0) {
            long sum = 0;
            for (int i = 0; i < 10; i++) {
                sum += digits[i];
            }
            long res = 0;
            if (sum % k == 0) {
                res += factorial(sum);
            }
            if (sum >= 2 && (sum - 2) % k == 0) {
                res += sum * (sum - 1) / 2;
            }
            return res;
        }
        long count = 0;
        int to = limit ? 9 : 9;
        for (int i = 0; i <= to; i++) {
            if (i == last && digits[i] > 1) {
                digits[i]--;
                count += helper(n - 1, k, i, digits, limit && i == to);
                digits[i]++;
            } else if (i != last) {
                digits[i]--;
                count += helper(n - 1, k, i, digits, limit && i == to);
                digits[i]++;
            }
        }
        return count;
    }

    private long factorial(long n) {
        long res = 1;
        for (int i = 1; i <= n; i++) {
            res *= i;
        }
        return res;
    }
}
